{"code": "import json

# Read the full business data
with open('/tmp/tmp0yuew0y8.json', 'r') as f:
    businesses = json.load(f)

# Filter businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    attributes = business.get('attributes')
    if attributes and isinstance(attributes, dict):
        if attributes.get('BusinessAcceptsCreditCards') == 'True':
            credit_card_businesses.append(business)

# Extract categories from description
import re

category_count = {}
business_categories = {}

for business in credit_card_businesses:
    desc = business.get('description', '')
    # Extract categories from description

    # Look for patterns like "services in X, Y, Z" or "fields of X, Y, Z"
    if 'services in' in desc:
        parts = desc.split('services in')
        if len(parts) > 1:
            categories_part = parts[1].split('.')[0].strip()
            categories = [cat.strip() for cat in categories_part.split(',')]
        elif 'fields of' in desc:
            parts = desc.split('fields of')
            if len(parts) > 1:
                categories_part = parts[1].split('.')[0].strip()
                categories = [cat.strip() for cat in categories_part.split(',')]
        elif 'including' in desc:
            parts = desc.split('including')
            if len(parts) > 1:
                categories_part = parts[1].split('.')[0].strip()
                categories = [cat.strip() for cat in categories_part.split(',')]
        else:
            categories = []
    elif 'fields of' in desc:
        parts = desc.split('fields of')
        if len(parts) > 1:
            categories_part = parts[1].split('.')[0].strip()
            categories = [cat.strip() for cat in categories_part.split(',')]
        else:
            categories = []
    elif 'including' in desc:
        parts = desc.split('including')
        if len(parts) > 1:
            categories_part = parts[1].split('.')[0].strip()
            categories = [cat.strip() for cat in categories_part.split(',')]
        else:
            categories = []
    else:
        categories = []

    business_id = business['business_id']
    business_categories[business_id] = categories

    for category in categories:
        category_count[category] = category_count.get(category, 0) + 1

# Sort categories by count
sorted_categories = sorted(category_count.items(), key=lambda x: x[1], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'total_credit_card_businesses': len(credit_card_businesses),
    'top_categories': sorted_categories[:10],
    'business_categories': business_categories
}, indent=2))"}

